VALUES
  ('judicial-57112235-moex-00437', 'judicial-57112235', 'judicial-57112235-moex-112-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依相關矯正法規成立之各式會議或小組，其委員任期之規定，下列何者正確？', '["監獄外部視察小組任期1年，任期屆滿得續聘之", "假釋審查會外聘委員任期1年，期滿得續聘之", "妨害性自主罪與妨害風化罪受刑人強制身心治療及輔導教育篩選評估小組、治療評估小組及輔導評 估小組任期均為2年，期滿得續聘之", "外役監受刑人遴選小組委員任期3年，任期屆滿得續派（聘）任之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "7bed571ea996", "answer_pdf_sha1": "beb2a64cc59d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00438', 'judicial-57112235', 'judicial-57112235-moex-112-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關監獄執行死刑之規定，下列敘述何者錯誤？', '["執行死刑，應於當日告知本人", "監獄執行死刑之日期，依刑事訴訟法第461條規定，於法務部令到5日內執行之", "死刑定讞待執行者，應由檢察官簽發死刑確定待執行指揮書，交由監獄收容", "對死刑定讞待執行者，監獄得適度放寬其接見、通信，並依其意願提供作業及教化輔導之機會"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "7bed571ea996", "answer_pdf_sha1": "beb2a64cc59d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00439', 'judicial-57112235', 'judicial-57112235-moex-112-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '關於施用戒具、施以固定保護或收容於保護室，下列敘述何者正確？', '["施用戒具逾2小時者，監獄應製作紀錄使受刑人簽名並交付繕本", "每次施用戒具最長不得逾24小時", "施以固定保護，每次最長不得逾4小時", "收容於保護室，每次最長不得逾48小時"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "7bed571ea996", "answer_pdf_sha1": "beb2a64cc59d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00440', 'judicial-57112235', 'judicial-57112235-moex-111-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '關於罪刑法定原則，下列敘述何者正確？', '["保安處分並非刑罰，故不適用罪刑法定原則", "在有利於行為人時，可例外容許類推適用", "刑法未規定處罰之行為，可適用習慣法予以定罪", "沒收屬對物保安處分，故適用最有利於行為人之法律"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "60e8b39a1ddb", "answer_pdf_sha1": "3c86136ea7a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00441', 'judicial-57112235', 'judicial-57112235-moex-111-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '下列何者不成立刑法第185條之3危險駕駛罪？', '["甲酒後血液中酒精濃度達百分之零點一而駕駛公車", "甲吸食安非他命致不能安全駕駛而駕駛汽車", "甲一邊騎乘機車一邊吃泡麵", "甲吃完燒酒雞呼氣酒精濃度達每公升0.35毫克而騎機車回家"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "60e8b39a1ddb", "answer_pdf_sha1": "3c86136ea7a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00442', 'judicial-57112235', 'judicial-57112235-moex-111-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '有關空白刑法及其補充法令之變更的敘述，下列何者錯誤？', '["補充法令之內容僅涉及法律效果，無關犯罪之成立要件", "補充法令有變更時，實務見解認為無刑法第2條第1項之適用", "刑法第192條違背預防傳染病所公布之檢查或進口法令罪，屬空白刑法", "刑法第251條第1項第3款囤積行政院公告之生活必需用品而不應市銷售罪，屬空白刑法"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "60e8b39a1ddb", "answer_pdf_sha1": "3c86136ea7a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00443', 'judicial-57112235', 'judicial-57112235-moex-111-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '關於刑法第305條之恐嚇危安罪，下列敘述何者正確？', '["以散布裸照之事要脅他人，依實務見解不構成刑法第305條之罪", "以神鬼迷信之事恐嚇他人，依實務見解不構成刑法第305條之罪", "刑法第305條之罪之成立，以行為人確有實施加害行為為必要", "刑法第305條之罪為保護健康法益之犯罪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "60e8b39a1ddb", "answer_pdf_sha1": "3c86136ea7a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00444', 'judicial-57112235', 'judicial-57112235-moex-111-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '甲搭乘捷運，離開捷運站時，發現身後有乙尾隨，甲誤以為乙要行搶，因此在乙靠近甲時，甲反手毆 打乙一拳，致乙受傷，事後發現，乙只是路人而已。有關本案的錯誤類型，何者正確？', '["客體錯誤", "打擊錯誤", "容許構成要件錯誤", "包攝錯誤"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "60e8b39a1ddb", "answer_pdf_sha1": "3c86136ea7a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00445', 'judicial-57112235', 'judicial-57112235-moex-111-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '甲持刀砍殺乙，已經砍了三刀非致命部分，過程中乙不斷向甲求饒，甲原不予理會，但突然聽到警車 經過聲響，擔心被捕而罷手，乙因而逃過一死。有關此情形，下列敘述何者錯誤？', '["甲之罷手並非出於自主動機，故不屬出於己意", "甲成立殺人罪之障礙未遂犯", "依刑法規定，甲應減輕或免除其刑", "甲之侵害情狀僅達未了未遂之階段"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "60e8b39a1ddb", "answer_pdf_sha1": "3c86136ea7a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00446', 'judicial-57112235', 'judicial-57112235-moex-111-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '關於未遂犯，下列敘述何者正確？', '["未遂犯之處罰，應按既遂犯之刑減輕之", "甲基於殺乙的意思，朝乙開槍未中，甲僅成立殺人預備犯", "幻覺犯亦屬於未遂犯", "中止犯屬於未遂犯"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "60e8b39a1ddb", "answer_pdf_sha1": "3c86136ea7a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL)
